class RateLimiter:
    """Simple in-memory rate limiter per peer."""

    def __init__(self, max_requests: int = 60, window_seconds: int = 60):
        self._max_requests = max_requests
        self._window_seconds = window_seconds
        self._requests: dict[str, list[float]] = {}

    def is_allowed(self, peer: str) -> bool:
        now = time.time()
        if peer not in self._requests:
            self._requests[peer] = []

        # Clean old entries
        self._requests[peer] = [
            t for t in self._requests[peer]
            if now - t < self._window_seconds
        ]

        if len(self._requests[peer]) >= self._max_requests:
            return False

        self._requests[peer].append(now)
        return True


