class UserDatabase:
    """Simulated user database with secure password storage."""

    def __init__(self):
        self._users: dict[str, dict] = {}
        # Seed with a test user (password hashed, never stored in plaintext)
        self._seed_users()

    def _seed_users(self):
        users_to_seed = [
            {
                "user_id": "user_001",
                "username": "alice",
                "password": "SecureP@ss1234",
                "email": "alice@example.com",
                "role": "admin"
            },
            {
                "user_id": "user_002",
                "username": "bob",
                "password": "An0therSecure!",
                "email": "bob@example.com",
                "role": "user"
            },
        ]
        for user in users_to_seed:
            self._users[user["username"]] = {
                "user_id": user["user_id"],
                "username": user["username"],
                "password_hash": PasswordHasher.hash_password(user["password"]),
                "email": user["email"],
                "role": user["role"]
            }

    def authenticate(self, username: str, password: str) -> Optional[dict]:
        user = self._users.get(username)
        if not user:
            # Still hash to prevent timing attacks revealing user existence
            PasswordHasher.hash_password(password)
            return None
        if PasswordHasher.verify_password(password, user["password_hash"]):
            return {
                "user_id": user["user_id"],
                "username": user["username"],
                "email": user["email"],
                "role": user["role"]
            }
        return None

    def get_user(self, user_id: str) -> Optional[dict]:
        for user in self._users.values():
            if user["user_id"] == user_id:
                return {
                    "user_id": user["user_id"],
                    "username": user["username"],
                    "email": user["email"],
                    "role": user["role"]
                }
        return None

    def list_users(self, page: int, page_size: int) -> tuple[list[dict], int]:
        all_users = [
            {
                "user_id": u["user_id"],
                "username": u["username"],
                "email": u["email"],
                "role": u["role"]
            }
            for u in self._users.values()
        ]
        total = len(all_users)
        start = page * page_size
        end = start + page_size
        return all_users[start:end], total


