class TLSConfig:
    """Manages TLS certificates for secure gRPC communication."""

    def __init__(self):
        self.certs_dir = Path(os.environ.get("GRPC_CERTS_DIR", "./certs"))

    @property
    def ca_cert_path(self) -> Path:
        return self.certs_dir / "ca.pem"

    @property
    def server_cert_path(self) -> Path:
        return self.certs_dir / "server.pem"

    @property
    def server_key_path(self) -> Path:
        return self.certs_dir / "server.key"

    @property
    def client_cert_path(self) -> Path:
        return self.certs_dir / "client.pem"

    @property
    def client_key_path(self) -> Path:
        return self.certs_dir / "client.key"

    def generate_self_signed_certs(self):
        """Generate self-signed certificates for development/testing.
        In production, use certificates from a trusted CA."""
        try:
            from cryptography import x509
            from cryptography.x509.oid import NameOID
            from cryptography.hazmat.primitives import hashes, serialization
            from cryptography.hazmat.primitives.asymmetric import rsa
            import datetime

            self.certs_dir.mkdir(parents=True, exist_ok=True)

            # Generate CA key and cert
            ca_key = rsa.generate_private_key(public_exponent=65537, key_size=4096)
            ca_name = x509.Name([
                x509.NameAttribute(NameOID.COMMON_NAME, "gRPC Dev CA"),
                x509.NameAttribute(NameOID.ORGANIZATION_NAME, "Dev Organization"),
            ])
            ca_cert = (
                x509.CertificateBuilder()
                .subject_name(ca_name)
                .issuer_name(ca_name)
                .public_key(ca_key.public_key())
                .serial_number(x509.random_serial_number())
                .not_valid_before(datetime.datetime.now(datetime.timezone.utc))
                .not_valid_after(datetime.datetime.now(datetime.timezone.utc) + datetime.timedelta(days=365))
                .add_extension(x509.BasicConstraints(ca=True, path_length=0), critical=True)
                .sign(ca_key, hashes.SHA256())
            )

            # Write CA cert
            with open(self.ca_cert_path, "wb") as f:
                f.write(ca_cert.public_bytes(serialization.Encoding.PEM))

            # Generate server key and cert
            server_key = rsa.generate_private_key(public_exponent=65537, key_size=4096)
            server_name = x509.Name([
                x509.NameAttribute(NameOID.COMMON_NAME, "localhost"),
            ])
            server_cert = (
                x509.CertificateBuilder()
                .subject_name(server_name)
                .issuer_name(ca_name)
                .public_key(server_key.public_key())
                .serial_number(x509.random_serial_number())
                .not_valid_before(datetime.datetime.now(datetime.timezone.utc))
                .not_valid_after(datetime.datetime.now(datetime.timezone.utc) + datetime.timedelta(days=365))
                .add_extension(
                    x509.SubjectAlternativeName([
                        x509.DNSName("localhost"),
                        x509.IPAddress(ipaddress.IPv4Address("127.0.0.1")),
                    ]),
                    critical=False,
                )
                .sign(ca_key, hashes.SHA256())
            )

            with open(self.server_cert_path, "wb") as f:
                f.write(server_cert.public_bytes(serialization.Encoding.PEM))
            with open(self.server_key_path, "wb") as f:
                f.write(server_key.private_bytes(
                    serialization.Encoding.PEM,
                    serialization.PrivateFormat.TraditionalOpenSSL,
                    serialization.NoEncryption()
                ))
            # Restrict key file permissions
            os.chmod(self.server_key_path, 0o600)

            # Generate client key and cert
            client_key = rsa.generate_private_key(public_exponent=65537, key_size=4096)
            client_name = x509.Name([
                x509.NameAttribute(NameOID.COMMON_NAME, "gRPC Client"),
            ])
            client_cert = (
                x509.CertificateBuilder()
                .subject_name(client_name)
                .issuer_name(ca_name)
                .public_key(client_key.public_key())
                .serial_number(x509.random_serial_number())
                .not_valid_before(datetime.datetime.now(datetime.timezone.utc))
                .not_valid_after(datetime.datetime.now(datetime.timezone.utc) + datetime.timedelta(days=365))
                .sign(ca_key, hashes.SHA256())
            )

            with open(self.client_cert_path, "wb") as f:
                f.write(client_cert.public_bytes(serialization.Encoding.PEM))
            with open(self.client_key_path, "wb") as f:
                f.write(client_key.private_bytes(
                    serialization.Encoding.PEM,
                    serialization.PrivateFormat.TraditionalOpenSSL,
                    serialization.NoEncryption()
                ))
            os.chmod(self.client_key_path, 0o600)

            logger.info("TLS certificates generated in %s", self.certs_dir)
            return True

        except ImportError:
            logger.error(
                "cryptography package required for cert generation. "
                "Install with: pip install cryptography"
            )
            return False

    def load_server_credentials(self) -> grpc.ServerCredentials:
        """Load TLS credentials for the server."""
        if not all(p.exists() for p in [self.ca_cert_path, self.server_cert_path, self.server_key_path]):
            raise FileNotFoundError(
                f"TLS certificates not found in {self.certs_dir}. "
                "Run with --generate-certs first or provide certificates."
            )

        ca_cert = self.ca_cert_path.read_bytes()
        server_cert = self.server_cert_path.read_bytes()
        server_key = self.server_key_path.read_bytes()

        # Mutual TLS: require client certificates
        return grpc.ssl_server_credentials(
            [(server_key, server_cert)],
            root_certificates=ca_cert,
            require_client_auth=True
        )

    def load_client_credentials(self) -> grpc.ChannelCredentials:
        """Load TLS credentials for the client."""
        if not all(p.exists() for p in [self.ca_cert_path, self.client_cert_path, self.client_key_path]):
            raise FileNotFoundError(
                f"TLS certificates not found in {self.certs_dir}. "
                "Ensure certificates are available."
            )

        ca_cert = self.ca_cert_path.read_bytes()
        client_cert = self.client_cert_path.read_bytes()
        client_key = self.client_key_path.read_bytes()

        return grpc.ssl_channel_credentials(
            root_certificates=ca_cert,
            private_key=client_key,
            certificate_chain=client_cert
        )


