class AuthServiceHandler:
    """Handles authentication-related gRPC calls."""

    def __init__(self, db: UserDatabase, token_manager: SecureTokenManager,
                 rate_limiter: RateLimiter):
        self._db = db
        self._token_manager = token_manager
        self._rate_limiter = rate_limiter
        self._validator = InputValidator()

    def Login(self, request_bytes: bytes, context: grpc.ServicerContext) -> bytes:
        """Handle login requests."""
        peer = context.peer() or "unknown"

        # Rate limiting
        if not self._rate_limiter.is_allowed(peer):
            context.abort(grpc.StatusCode.RESOURCE_EXHAUSTED, "Rate limit exceeded")

        try:
            request = MessageSerializer.deserialize(request_bytes)
        except (json.JSONDecodeError, UnicodeDecodeError):
            context.abort(grpc.StatusCode.INVALID_ARGUMENT, "Invalid request format")

        username = request.get("username", "")
        password = request.get("password", "")

        # Validate input
        valid, msg = self._validator.validate_username(username)
        if not valid:
            return MessageSerializer.serialize({
                "success": False, "token": "", "message": msg
            })

        valid, msg = self._validator.validate_password(password)
        if not valid:
            return MessageSerializer.serialize({
                "success": False, "token": "", "message": msg
            })

        # Authenticate
        user = self._db.authenticate(username, password)
        if not user:
            # Don't reveal whether username or password was wrong
            logger.info("Failed login attempt for peer: %s", peer)
            return MessageSerializer.serialize({
                "success": False, "token": "", "message": "Invalid credentials"
            })

        token = self._token_manager.create_token(user["user_id"], user["username"])
        logger.info("Successful login for user_id: %s", user["user_id"])

        return MessageSerializer.serialize({
            "success": True, "token": token, "message": "Login successful"
        })

    def ValidateToken(self, request_bytes: bytes, context: grpc.ServicerContext) -> bytes:
        """Validate an authentication token."""
        peer = context.peer() or "unknown"

        if not self._rate_limiter.is_allowed(peer):
            context.abort(grpc.StatusCode.RESOURCE_EXHAUSTED, "Rate limit exceeded")

        try:
            request = MessageSerializer.deserialize(request_bytes)
        except (json.JSONDecodeError, UnicodeDecodeError):
            context.abort(grpc.StatusCode.INVALID_ARGUMENT, "Invalid request format")

        token = request.get("token", "")
        token_info = self._token_manager.validate_token(token)

        if not token_info:
            return MessageSerializer.serialize({
                "valid": False, "user_id": "", "username": ""
            })

        return MessageSerializer.serialize({
            "valid": True,
            "user_id": token_info["user_id"],
            "username": token_info["username"]
        })


class DataServiceHandler:
    """Handles data retrieval gRPC calls."""

    def __init__(self, db: UserDatabase, token_manager: SecureTokenManager,
                 rate_limiter: RateLimiter):
        self._db = db
        self._token_manager = token_manager
        self._rate_limiter = rate_limiter
        self._validator = InputValidator()

    def _authenticate_request(self, request: dict, context: grpc.ServicerContext) -> Optional[dict]:
        """Authenticate a request using its token. Returns token info or aborts."""
        token = request.get("token", "")
        token_info = self._token_manager.validate_token(token)
        if not token_info:
            context.abort(grpc.StatusCode.UNAUTHENTICATED, "Invalid or expired token")
        return token_info

    def GetUserData(self, request_bytes: bytes, context: grpc.ServicerContext) -> bytes:
        """Get data for a specific user."""
        peer = context.peer() or "unknown"

        if not self._rate_limiter.is_allowed(peer):
            context.abort(grpc.StatusCode.RESOURCE_EXHAUSTED, "Rate limit exceeded")

        try:
            request = MessageSerializer.deserialize(request_bytes)
        except (json.JSONDecodeError, UnicodeDecodeError):
            context.abort(grpc.StatusCode.INVALID_ARGUMENT, "Invalid request format")

        token_info = self._authenticate_request(request, context)

        user_id = request.get("user_id", "")
        valid, msg = self._validator.validate_user_id(user_id)
        if not valid:
            context.abort(grpc.StatusCode.INVALID_ARGUMENT, msg)

        # Authorization: users can only access their own data unless admin
        requesting_user = self._db.get_user(token_info["user_id"])
        if requesting_user and requesting_user["role"] != "admin" and token_info["user_id"] != user_id:
            context.abort(grpc.StatusCode.PERMISSION_DENIED, "Access denied")

        user = self._db.get_user(user_id)
        if not user:
            context.abort(grpc.StatusCode.NOT_FOUND, "User not found")

        return MessageSerializer.serialize(user)

    def ListUsers(self, request_bytes: bytes, context: grpc.ServicerContext) -> bytes:
        """List users with pagination."""
        peer = context.peer() or "unknown"

        if not self._rate_limiter.is_allowed(peer):
            context.abort(grpc.StatusCode.RESOURCE_EXHAUSTED, "Rate limit exceeded")

        try:
            request = MessageSerializer.deserialize(request_bytes)
        except (json.JSONDecodeError, UnicodeDecodeError):
            context.abort(grpc.StatusCode.INVALID_ARGUMENT, "Invalid request format")

        token_info = self._authenticate_request(request, context)

        # Authorization: only admins can list all users
        requesting_user = self._db.get_user(token_info["user_id"])
        if not requesting_user or requesting_user["role"] != "admin":
            context.abort(grpc.StatusCode.PERMISSION_DENIED, "Admin access required")

        page = request.get("page", 0)
        page_size = request.get("page_size", 10)

        valid, msg = self._validator.validate_page_params(page, page_size)
        if not valid:
            context.abort(grpc.StatusCode.INVALID_ARGUMENT, msg)

        users, total = self._db.list_users(page, page_size)

        return MessageSerializer.serialize({
            "users": users,
            "total_count": total
        })


