def create_method_handler(handler_func):
    """Create a unary-unary method handler."""
    return grpc.unary_unary_rpc_method_handler(
        lambda request, context: handler_func(request, context),
        request_deserializer=None,
        response_serializer=None,
    )


class UserServiceGenericHandler(grpc.GenericRpcHandler):
    """Routes gRPC calls to appropriate service handlers."""

    def __init__(self, auth_handler: AuthServiceHandler, data_handler: DataServiceHandler):
        self._auth_handler = auth_handler
        self._data_handler = data_handler

        self._method_handlers = {
            "/userservice.AuthService/Login": self._make_handler(auth_handler.Login),
            "/userservice.AuthService/ValidateToken": self._make_handler(auth_handler.ValidateToken),
            "/userservice.DataService/GetUserData": self._make_handler(data_handler.GetUserData),
            "/userservice.DataService/ListUsers": self._make_handler(data_handler.ListUsers),
        }

    def _make_handler(self, func):
        return grpc.unary_unary_rpc_method_handler(
            func,
            request_deserializer=None,
            response_serializer=None,
        )

    def service(self, handler_call_details):
        method = handler_call_details.method
        return self._method_handlers.get(method)


def serve(port: int = 50051, generate_certs: bool = False):
    """Start the gRPC server with TLS."""
    tls_config = TLSConfig()

    if generate_certs:
        if not tls_config.generate_self_signed_certs():
            logger.error("Failed to generate certificates")
            return

    # Initialize components
    token_manager = SecureTokenManager()
    db = UserDatabase()
    rate_limiter = RateLimiter(max_requests=100, window_seconds=60)

    auth_handler = AuthServiceHandler(db, token_manager, rate_limiter)
    data_handler = DataServiceHandler(db, token_manager, rate_limiter)

    # Create server with thread pool (limit concurrency)
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        maximum_concurrent_rpcs=100,
        options=[
            ('grpc.max_receive_message_length', 1024 * 1024),  # 1MB max
            ('grpc.max_send_message_length', 1024 * 1024),
            ('grpc.max_metadata_size', 8192),
        ]
    )

    # Register service handlers
    generic_handler = UserServiceGenericHandler(auth_handler, data_handler)
    server.add_generic_rpc_handlers([generic_handler])

    # SECURE: Always use TLS - never use insecure_channel/port
    try:
        server_credentials = tls_config.load_server_credentials()
        bound_port = server.add_secure_port(f"[::]:{port}", server_credentials)
        if bound_port == 0:
            logger.error("Failed to bind to port %d", port)
            return
        logger.info("gRPC server starting on port %d with mutual TLS", bound_port)
    except FileNotFoundError as e:
        logger.error(str(e))
        logger.error("Run with --generate-certs to create development certificates")
        return

    server.start()
    logger.info("Server is running. Press Ctrl+C to stop.")

    try:
        server.wait_for_termination()
    except KeyboardInterrupt:
        logger.info("Shutting down server...")
        server.stop(grace=5)
        logger.info("Server stopped.")


# ============================================================
# gRPC Client
# ============================================================

class SecureGRPCClient:
    """gRPC client that connects using TLS (never insecure)."""

    def __init__(self, host: str = "localhost", port: int = 50051):
        self._host = host
        self._port = port
        self._tls_config = TLSConfig()
        self._channel = None
        self._token = None

    def connect(self):
        """Establish a secure TLS connection to the server."""
        # SECURE: Use ssl_channel_credentials, never insecure_channel
        credentials = self._tls_config.load_client_credentials()

        self._channel = grpc.secure_channel(
            f"{self._host}:{self._port}",
            credentials,
            options=[
                ('grpc.max_receive_message_length', 1024 * 1024),
                ('grpc.max_send_message_length', 1024 * 1024),
                # Override SSL target name for localhost development
                ('grpc.ssl_target_name_override', 'localhost'),
            ]
        )
        logger.info("Connected to %s:%d with TLS", self._host, self._port)

    def close(self):
        """Close the channel."""
        if self._channel:
            self._channel.close()
            self._channel = None

    def _call(self, method: str, request: dict) -> dict:
        """Make a unary-unary gRPC call."""
        if not self._channel:
            raise RuntimeError("Not connected. Call connect() first.")

        request_bytes = MessageSerializer.serialize(request)

        # Create a callable for the method
        call = self._channel.unary_unary(
            method,
            request_serializer=None,
            response_deserializer=None,
        )

        try:
            response_bytes = call(request_bytes, timeout=10)
            return MessageSerializer.deserialize(response_bytes)
        except grpc.RpcError as e:
            logger.error("gRPC error: %s - %s", e.code(), e.details())
            raise

    def login(self, username: str, password: str) -> dict:
        """Authenticate with the server."""
        response = self._call(
            "/userservice.AuthService/Login",
            {"username": username, "password": password}
        )
        if response.get("success"):
            self._token = response["token"]
        return response

    def validate_token(self) -> dict:
        """Validate the current token."""
        if not self._token:
            return {"valid": False, "user_id": "", "username": ""}
        return self._call(
            "/userservice.AuthService/ValidateToken",
            {"token": self._token}
        )

    def get_user_data(self, user_id: str) -> dict:
        """Get data for a specific user."""
        if not self._token:
            raise RuntimeError("Not authenticated. Call login() first.")
        return self._call(
            "/userservice.DataService/GetUserData",
            {"token": self._token, "user_id": user_id}
        )

    def list_users(self, page: int = 0, page_size: int = 10) -> dict:
        """List users (admin only)."""
        if not self._token:
            raise RuntimeError("Not authenticated. Call login() first.")
        return self._call(
            "/userservice.DataService/ListUsers",
            {"token": self._token, "page": page, "page_size": page_size}
        )


# ============================================================
# Main entry point
# ============================================================

def run_client_demo():
    """Demonstrate client usage."""
    client = SecureGRPCClient("localhost", 50051)

    try:
        client.connect()

        # Login as alice (admin)
        print("\n--- Login as alice ---")
        result = client.login("alice", "SecureP@ss1234")
        print(f"Login result: success={result['success']}, message={result['message']}")

        # Validate token
        print("\n--- Validate Token ---")
        result = client.validate_token()
        print(f"Token valid: {result['valid']}, user: {result.get('username', 'N/A')}")

        # Get user data
        print("\n--- Get User Data (own) ---")
        result = client.get_user_data("user_001")
        print(f"User: {result}")

        # Get another user's data (admin can do this)
        print("\n--- Get User Data (other user, as admin) ---")
        result = client.get_user_data("user_002")
        print(f"User: {result}")

        # List users (admin only)
        print("\n--- List Users ---")
        result = client.list_users(page=0, page_size=10)
        print(f"Users: {result['users']}, Total: {result['total_count']}")

        # Login as bob (regular user)
        print("\n--- Login as bob ---")
        result = client.login("bob", "An0therSecure!")
        print(f"Login result: success={result['success']}")

        # Try to list users as bob (should fail - not admin)
        print("\n--- List Users as bob (should fail) ---")
        try:
            result = client.list_users()
        except grpc.RpcError as e:
            print(f"Expected error: {e.code()} - {e.details()}")

        # Try to access alice's data as bob (should fail - not admin)
        print("\n--- Get alice's data as bob (should fail) ---")
        try:
            result = client.get_user_data("user_001")
        except grpc.RpcError as e:
            print(f"Expected error: {e.code()} - {e.details()}")

        # Bob can access own data
        print("\n--- Get own data as bob ---")
        result = client.get_user_data("user_002")
        print(f"User: {result}")

        # Test invalid login
        print("\n--- Invalid Login ---")
        result = client.login("alice", "wrongpassword")
        print(f"Login result: success={result['success']}, message={result['message']}")

    except Exception as e:
        logger.error("Client error: %s", e)
    finally:
        client.close()


if __name__ == "__main__":
    import sys

    if len(sys.argv) < 2:
        print("Usage:")
        print("  python grpc_microservice.py generate-certs  - Generate TLS certificates")
        print("  python grpc_microservice.py server           - Start the gRPC server")
        print("  python grpc_microservice.py client           - Run the client demo")
        print()
        print("Environment variables required:")
        print("  TOKEN_SECRET_KEY  - Secret key for token signing")
        print("  GRPC_CERTS_DIR   - Directory for TLS certificates (default: ./certs)")
        print()
        print("Quick start:")
        print("  export TOKEN_SECRET_KEY=$(python -c \"import secrets; print(secrets.token_hex(64))\")")
        print("  python grpc_microservice.py generate-certs")
        print("  python grpc_microservice.py server  # in one terminal")
        print("  python grpc_microservice.py client  # in another terminal")
        sys.exit(1)

    command = sys.argv[1].lower()

    if command == "generate-certs":
        # Set a dummy token key just for cert generation
        if not os.environ.get("TOKEN_SECRET_KEY"):
            os.environ["TOKEN_SECRET_KEY"] = "dummy-for-cert-gen"
        tls = TLSConfig()
        tls.generate_self_signed_certs()
    elif command == "server":
        serve(port=50051)
    elif command == "client":
        run_client_demo()
    else:
        print(f"Unknown command: {command}")
        sys.exit(1)